import React, { useState, useMemo } from 'react';
import { Calendar, Plane, TrendingUp, Clock, MapPin } from 'lucide-react';

const VacationPlanner = ({ holidays, vacations, leaveBalances: initialLeaveBalances }) => {
  const [leaveBalances, setLeaveBalances] = useState(initialLeaveBalances || { EL: 30, SL: 6, CL: 3 });
  const [isEditingBalances, setIsEditingBalances] = useState(false);
  // Find long weekend opportunities (holidays on Monday/Friday)
  const longWeekendOpportunities = useMemo(() => {
    return holidays.filter(holiday => {
      const date = new Date(holiday.date);
      const dayOfWeek = date.getDay();
      return dayOfWeek === 1 || dayOfWeek === 5; // Monday (1) or Friday (5)
    });
  }, [holidays]);

  // Calculate total vacation days
  const totalVacationDays = useMemo(() => {
    return vacations.reduce((total, vacation) => {
      // Handle both old and new field names
      const start = new Date(vacation.fromDate || vacation.startDate);
      const end = new Date(vacation.toDate || vacation.endDate);
      const days = Math.ceil((end - start) / (1000 * 60 * 60 * 24)) + 1;
      return total + days;
    }, 0);
  }, [vacations]);

  // Format date for display
  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric'
    });
  };

  // Get day name
  const getDayName = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', { weekday: 'long' });
  };

  return (
    <div className="space-y-6">
      {/* Leave Balance Summary */}
      <div className="bg-white rounded-lg shadow p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center justify-between">
          <div className="flex items-center">
            <TrendingUp className="w-5 h-5 mr-2 text-purple-600" />
            Leave Balance
          </div>
          <button
            onClick={() => setIsEditingBalances(!isEditingBalances)}
            className="text-sm px-3 py-1 bg-purple-100 text-purple-700 rounded-lg hover:bg-purple-200 transition-colors duration-200"
          >
            {isEditingBalances ? 'Save' : 'Edit'}
          </button>
        </h3>

        <div className="grid grid-cols-3 gap-4">
          <div className="text-center p-3 bg-blue-50 rounded-lg">
            {isEditingBalances ? (
              <input
                type="number"
                value={leaveBalances?.EL || 30}
                onChange={(e) => setLeaveBalances(prev => ({ ...prev, EL: parseInt(e.target.value) || 0 }))}
                className="w-full text-2xl font-bold text-blue-600 bg-transparent border-b-2 border-blue-300 focus:outline-none focus:border-blue-500 text-center"
                min="0"
              />
            ) : (
              <div className="text-2xl font-bold text-blue-600">
                {leaveBalances?.EL || 30}
              </div>
            )}
            <div className="text-sm text-blue-800">Earned Leave</div>
          </div>

          <div className="text-center p-3 bg-green-50 rounded-lg">
            {isEditingBalances ? (
              <input
                type="number"
                value={leaveBalances?.SL || 6}
                onChange={(e) => setLeaveBalances(prev => ({ ...prev, SL: parseInt(e.target.value) || 0 }))}
                className="w-full text-2xl font-bold text-green-600 bg-transparent border-b-2 border-green-300 focus:outline-none focus:border-green-500 text-center"
                min="0"
              />
            ) : (
              <div className="text-2xl font-bold text-green-600">
                {leaveBalances?.SL || 6}
              </div>
            )}
            <div className="text-sm text-green-800">Sick Leave</div>
          </div>

          <div className="text-center p-3 bg-yellow-50 rounded-lg">
            {isEditingBalances ? (
              <input
                type="number"
                value={leaveBalances?.CL || 3}
                onChange={(e) => setLeaveBalances(prev => ({ ...prev, CL: parseInt(e.target.value) || 0 }))}
                className="w-full text-2xl font-bold text-yellow-600 bg-transparent border-b-2 border-yellow-300 focus:outline-none focus:border-green-500 text-center"
                min="0"
              />
            ) : (
              <div className="text-2xl font-bold text-yellow-600">
                {leaveBalances?.CL || 3}
              </div>
            )}
            <div className="text-sm text-yellow-800">Casual Leave</div>
          </div>
        </div>
      </div>

      {/* Long Weekend Opportunities */}
      <div className="bg-white rounded-lg shadow p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
          <Calendar className="w-5 h-5 mr-2 text-orange-600" />
          Long Weekend Opportunities
        </h3>

        {longWeekendOpportunities.length === 0 ? (
          <p className="text-gray-500 text-sm">No long weekend opportunities found.</p>
        ) : (
          <div className="space-y-3">
            {longWeekendOpportunities.map((holiday) => (
              <div
                key={holiday._id}
                className="p-3 bg-orange-50 border border-orange-200 rounded-lg"
              >
                <div className="flex items-center justify-between">
                  <div>
                    <h4 className="font-medium text-orange-900">{holiday.name}</h4>
                    <p className="text-sm text-orange-700">
                      {getDayName(holiday.date)} • {formatDate(holiday.date)}
                    </p>
                  </div>
                  <div className="text-xs bg-orange-200 text-orange-800 px-2 py-1 rounded-full">
                    {getDayName(holiday.date).substring(0, 3)}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Planned Vacations */}
      <div className="bg-white rounded-lg shadow p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
          <Plane className="w-5 h-5 mr-2 text-green-600" />
          Planned Vacations
        </h3>

        {vacations.length === 0 ? (
          <p className="text-gray-500 text-sm">No vacations planned yet.</p>
        ) : (
          <div className="space-y-3">
            {vacations.map((vacation) => (
              <div
                key={vacation._id}
                className="p-3 bg-green-50 border border-green-200 rounded-lg"
              >
                <div className="flex items-center justify-between mb-2">
                  <h4 className="font-medium text-green-900">{vacation.name}</h4>
                  <div className="flex items-center text-sm text-green-700">
                    <Clock className="w-3 h-3 mr-1" />
                    {vacation.days || vacation.duration || 'N/A'} days
                  </div>
                </div>

                <div className="flex items-center text-sm text-green-700">
                  <MapPin className="w-3 h-3 mr-1" />
                  {formatDate(vacation.fromDate || vacation.startDate)} - {formatDate(vacation.toDate || vacation.endDate)}
                </div>

                {vacation.description && (
                  <p className="text-sm text-green-600 mt-2 italic">
                    "{vacation.description}"
                  </p>
                )}
              </div>
            ))}
          </div>
        )}

        {vacations.length > 0 && (
          <div className="mt-4 p-3 bg-blue-50 border border-blue-200 rounded-lg">
            <div className="flex items-center justify-between text-sm">
              <span className="text-blue-800">Total Vacation Days:</span>
              <span className="font-semibold text-blue-900">{totalVacationDays} days</span>
            </div>
          </div>
        )}
      </div>

      {/* Quick Stats */}
      <div className="bg-white rounded-lg shadow p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Quick Stats</h3>

        <div className="space-y-3 text-sm">
          <div className="flex justify-between">
            <span className="text-gray-600">Total Holidays:</span>
            <span className="font-medium text-gray-900">{holidays.length}</span>
          </div>

          <div className="flex justify-between">
            <span className="text-gray-600">Total Vacations:</span>
            <span className="font-medium text-gray-900">{vacations.length}</span>
          </div>

          <div className="flex justify-between">
            <span className="text-gray-600">Long Weekends:</span>
            <span className="font-medium text-gray-900">{longWeekendOpportunities.length}</span>
          </div>

          <div className="flex justify-between">
            <span className="text-gray-600">Total Vacation Days:</span>
            <span className="font-medium text-gray-900">{totalVacationDays}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default VacationPlanner;
